# Find all double-quoted substrings and their positions
quotes = []
i = 0
while True:
    start = content.find('"', i)
    if start == -1:
        break
    end = content.find('"', start+1)
    if end == -1:
        break
    quotes.append((start, end, content[start+1:end]))
    i = end+1

len(quotes), quotes[:3]
